// Pull both ensures into the proof context so the `=~=` triggers on
// `pre_self_.seq@.update(i as int, out)` fire for each run.
assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
assert(post1_self_.wf());
assert(post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
assert(post2_self_.wf());

// Both post-state views equal the same updated sequence, so they are
// extensionally equal to each other.  Sequence ext-equality closes the
// determinism obligation for the only spec-observable field of `Array`.
assert(post1_self_.seq@ =~= post2_self_.seq@);
